import{_ as e,o as i,c as t,a0 as n}from"./chunks/framework.AQcSKqPn.js";const k=JSON.parse('{"title":"Makima","description":"","frontmatter":{"type":"entity","title":"Makima","tags":["chainsaw-man","devil-hunter","antagonist"],"related":["chainsaw-man-reze-movie","denji","reze","devil-hunter"],"sources":["anime/57555.md"],"created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"entities/makima.md","filePath":"entities/makima.md","lastUpdated":1783686903000}'),r={name:"entities/makima.md"};function m(l,a,s,o,d,h){return i(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="makima" tabindex="-1">Makima <a class="header-anchor" href="#makima" aria-label="Permalink to &quot;Makima&quot;">​</a></h1><p>Makima是《电锯人》系列中的精英<a href="/llm-wiki/concepts/恶魔猎人-devil-hunter">devil-hunter</a>，在《Chainsaw Man Movie: Reze-hen》中扮演关键推动者的角色。</p><h2 id="在《蕾塞篇》中的角色" tabindex="-1">在《蕾塞篇》中的角色 <a class="header-anchor" href="#在《蕾塞篇》中的角色" aria-label="Permalink to &quot;在《蕾塞篇》中的角色&quot;">​</a></h2><p>在电影中，Makima主动约<a href="/llm-wiki/entities/denji">denji</a>出去约会。这次约会强化了Denji对她的情感依赖，Denji甚至发誓不会爱上其他人。这一行为被解读为情感操控——Makima通过约会建立Denji对她的忠诚，为后续<a href="/llm-wiki/entities/reze">reze</a>的登场制造情感冲突。</p><h2 id="叙事功能" tabindex="-1">叙事功能 <a class="header-anchor" href="#叙事功能" aria-label="Permalink to &quot;叙事功能&quot;">​</a></h2><p>Makima的约会行为是典型的&quot;情感陷阱&quot;叙事手法，旨在巩固她对Denji的控制。这一情节为电影的情感三角冲突奠定了基础。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="/llm-wiki/sources/5-anime--5-57555--1y8c62s">5-anime--5-57555--1y8c62s</a> — MyAnimeList条目</li></ul>',8)])])}const u=e(r,[["render",m]]);export{k as __pageData,u as default};
